                                            <span onClick={(e) => { e.stopPropagation(); setExportLanguage('en'); }} className={`lang-pill-btn ${exportLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                                            <span onClick={(e) => { e.stopPropagation(); setExportLanguage('vi'); }} className={`lang-pill-btn ${exportLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                                        </div>
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>

            {/* Smart Calendar Modal */}
            <GlassDatePicker 
                isOpen={isCalendarOpen} 
                onClose={() => setIsCalendarOpen(false)}
                selectedDates={safeAuditDates}
                onChange={handleUpdateDates}
            />
        </div>
    );
};

import React, { createContext, useContext, useState, useEffect, useMemo, useRef } from 'react';
import { StandardsData, AuditInfo, AuditProcess, Standard, MatrixRow, EvidenceTag, AnalysisResult, PrivacySettings, AuditSite, AuditMember, AuditPlanConfig, AuditScheduleItem } from '../types';
import { DEFAULT_AUDIT_INFO, DEFAULT_PLAN_CONFIG, STANDARDS_DATA, INITIAL_EVIDENCE, AUDIT_TYPES as DEFAULT_AUDIT_TYPES } from '../constants';
import { KnowledgeStore } from '../services/knowledgeStore';

interface AuditContextType {
    // Standard
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (key: string) => void;
    customStandards: StandardsData;
    addCustomStandard: (key: string, std: Standard) => void;
    updateStandard: (std: Standard) => void;
    resetStandard: (key: string) => void;

    // Audit Info
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;

    // Privacy
    privacySettings: PrivacySettings;
    setPrivacySettings: React.Dispatch<React.SetStateAction<PrivacySettings>>;

    // Audit Types Management (Dynamic)
    auditTypeOptions: Record<string, string>;
    addAuditType: (type: string, objective: string) => void;
    deleteAuditType: (type: string) => void;
    resetAuditTypes: () => void;

    // Process Management
    processes: AuditProcess[];
    activeProcessId: string | null;
    activeProcess: AuditProcess | undefined;
    setActiveProcessId: (id: string | null) => void;
    addProcess: (name: string) => void;
    renameProcess: (id: string, name: string) => void;
    updateProcessCode: (id: string, code: string) => void;
    updateProcessSites: (id: string, siteIds: string[]) => void; // New
    deleteProcess: (id: string) => void;
    batchUpdateProcessClauses: (updates: { processId: string, clauses: string[] }[]) => void;
    toggleProcessClause: (processId: string, clauseId: string) => void; 

    // Interviewee Management
    addInterviewee: (name: string) => void;
    removeInterviewee: (name: string) => void;

    // Smart Planning (New)
    auditSites: AuditSite[];
    setAuditSites: React.Dispatch<React.SetStateAction<AuditSite[]>>;
    auditTeam: AuditMember[];
    setAuditTeam: React.Dispatch<React.SetStateAction<AuditMember[]>>;
    auditPlanConfig: AuditPlanConfig;
    setAuditPlanConfig: React.Dispatch<React.SetStateAction<AuditPlanConfig>>;
    auditSchedule: AuditScheduleItem[];
    setAuditSchedule: React.Dispatch<React.SetStateAction<AuditScheduleItem[]>>;

    // Active Data
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    evidenceTags: EvidenceTag[];
    addEvidenceTag: (tag: EvidenceTag) => void;

    // Selections
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;

    // Knowledge Base
    knowledgeBase: string | null;
    knowledgeFileName: string | null;
    loadKnowledgeForStandard: (key: string) => Promise<void>;
    clearKnowledge: () => void;
    setKnowledgeData: (content: string, fileName: string) => void;

    // Results
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    finalReportText: string | null;
    setFinalReportText: (text: string | null) => void;

    // Actions
    resetSession: () => void;
    restoreSession: (data: any) => void;
}

const AuditContext = createContext<AuditContextType | undefined>(undefined);

const DEFAULT_PRIVACY: PrivacySettings = {
    maskCompany: true,
    maskSmo: true,
    maskPeople: true,
    maskEmail: true,
    maskPhone: true,
    maskAddress: true,
    maskIP: true
};

export const AuditProvider = ({ children }: React.PropsWithChildren<{}>) => {
    // --- STATE ---
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [privacySettings, setPrivacySettings] = useState<PrivacySettings>(DEFAULT_PRIVACY);

    // Dynamic Audit Types
    const [auditTypeOptions, setAuditTypeOptions] = useState<Record<string, string>>(DEFAULT_AUDIT_TYPES);

    // Processes (Start Empty)
    const [processes, setProcesses] = useState<AuditProcess[]>([]);
    const [activeProcessId, setActiveProcessId] = useState<string | null>(null);

    // Smart Planning State
    const [auditSites, setAuditSites] = useState<AuditSite[]>([]);
    const [auditTeam, setAuditTeam] = useState<AuditMember[]>([]);
    const [auditPlanConfig, setAuditPlanConfig] = useState<AuditPlanConfig>(DEFAULT_PLAN_CONFIG);
    const [auditSchedule, setAuditSchedule] = useState<AuditScheduleItem[]>([]);

    // Active View Data
    const [loadedProcessId, setLoadedProcessId] = useState<string | null>(null);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [matrixData, setMatrixData] = useState<Record<string, MatrixRow[]>>({});
    const [evidenceTags, setEvidenceTags] = useState<EvidenceTag[]>([]);

    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // KB
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    // Analysis
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);

    const standards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);
    const activeProcess = useMemo(() => processes.find(p => p.id === activeProcessId), [processes, activeProcessId]);
    const processesRef = useRef(processes);
    useEffect(() => { processesRef.current = processes; }, [processes]);

    // --- INIT AUDIT TYPES ---
    useEffect(() => {
        const savedTypes = localStorage.getItem("iso_audit_types_config");
        if (savedTypes) {
            try {
                setAuditTypeOptions(JSON.parse(savedTypes));
            } catch (e) {
                console.error("Failed to load audit types config", e);
            }
        }
    }, []);

    // --- SYNC EFFECTS ---
    useEffect(() => {
        if (!activeProcessId) {
            setEvidence("");
            setMatrixData({});
            setEvidenceTags([]);
            setLoadedProcessId(null);
            return;
        }
        if (activeProcessId === loadedProcessId) return;

        const target = processesRef.current.find(p => p.id === activeProcessId);
        if (target) {
            setEvidence(target.evidence || "");
            setMatrixData(target.matrixData || {});
            setEvidenceTags(target.evidenceTags || []);
            setLoadedProcessId(activeProcessId);
        } else {
            setLoadedProcessId(null);
        }
    }, [activeProcessId, loadedProcessId]); 

    useEffect(() => {
        if (!loadedProcessId) return;
        setProcesses(prev => prev.map(p => {
            if (p.id === loadedProcessId) {
                if (p.evidence !== evidence || p.matrixData !== matrixData || p.evidenceTags !== evidenceTags) {
                    return { ...p, evidence, matrixData, evidenceTags };
                }
            }
            return p;
        }));
    }, [evidence, matrixData, evidenceTags, loadedProcessId]);

    // --- NEW: INTELLIGENT SYNC (Sites & Staff) ---
    // Mirrors the logic: Total must reflect reality of Planning allocations.
    useEffect(() => {
        const allocatedEmployees = auditSites.reduce((sum, s) => sum + (s.employeeCount || 0), 0);

        setAuditInfo(prev => {
            let next = { ...prev };
            let hasChange = false;

            // 1. Sync Total Sites Count (Strict Equality)
            if (prev.totalSites !== auditSites.length) {
                next.totalSites = auditSites.length;
                hasChange = true;
            }

            // 2. Sync Total Staff (Floor Constraint: Cap cannot be less than allocated)
            // Allows user to set buffer in Sidebar, but auto-expands if Planning needs more.
            const currentCap = prev.totalEmployees || 0;
            if (allocatedEmployees > currentCap) {
                next.totalEmployees = allocatedEmployees;
                hasChange = true;
            }

            return hasChange ? next : prev;
        });
    }, [auditSites, auditInfo.totalEmployees, auditInfo.totalSites]);

    // --- ACTIONS ---
    const addCustomStandard = (key: string, std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [key]: std }));
    };

    const updateStandard = (std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    };

    const resetStandard = (key: string) => {
        setCustomStandards(prev => {
            const next = { ...prev };
            delete next[key];
            return next;
        });
        if (standardKey === key) setStandardKey("");
    };

    // AUDIT TYPE MANAGEMENT
    const addAuditType = (type: string, objective: string) => {
        setAuditTypeOptions(prev => {
            const next = { ...prev, [type]: objective };
            localStorage.setItem("iso_audit_types_config", JSON.stringify(next));
            return next;
        });
    };

    const deleteAuditType = (type: string) => {
        setAuditTypeOptions(prev => {
            const next = { ...prev };
            delete next[type];
            localStorage.setItem("iso_audit_types_config", JSON.stringify(next));
            return next;
        });
    };

    const resetAuditTypes = () => {
        setAuditTypeOptions(DEFAULT_AUDIT_TYPES);
        localStorage.removeItem("iso_audit_types_config");
    };

    const addProcess = (name: string) => {
        const newId = `proc_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`;
        const newProcess = { 
            id: newId, 
            name, 
            evidence: "", 
            interviewees: [],
            matrixData: {}, 
            evidenceTags: [], 
            uploadedFiles: [],
            siteIds: []
        };
        setProcesses(prev => [...prev, newProcess]);
        setActiveProcessId(newId);
    };

    const renameProcess = (id: string, name: string) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, name } : p));
    };

    const updateProcessCode = (id: string, code: string) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, competencyCode: code } : p));
    };

    const updateProcessSites = (id: string, siteIds: string[]) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, siteIds } : p));
    };

    const deleteProcess = (idToDelete: string) => {
        if (activeProcessId === idToDelete) {
            setProcesses(prev => {
                const remaining = prev.filter(p => p.id !== idToDelete);
                const nextId = remaining.length > 0 ? remaining[0].id : null;
                setActiveProcessId(nextId);
                return remaining;
            });
        } else {
            setProcesses(prev => prev.filter(p => p.id !== idToDelete));
        }
    };

    const findClauseInStandard = (cid: string, standard: Standard | undefined): any => {
        if (!standard) return null;
        const allClauses = standard.groups.flatMap(g => g.clauses);
        const findRecursive = (id: string, list: any[]): any => {
            for (const c of list) {
                if (c.id === id) return c;
                if (c.subClauses) {
                    const found = findRecursive(id, c.subClauses);
                    if (found) return found;
                }
            }
            return null;
        };
        return findRecursive(cid, allClauses);
    };

    const batchUpdateProcessClauses = (updates: { processId: string, clauses: string[] }[]) => {
        setProcesses(prev => prev.map(p => {
            const update = updates.find(u => u.processId === p.id);
            if (update) {
                const newMatrixData = { ...p.matrixData };
                const standard = standards[standardKey];

                update.clauses.forEach(clauseId => {
                    if (!newMatrixData[clauseId]) {
                        const clause = findClauseInStandard(clauseId, standard);
                        const desc = clause?.description || "Requirement";
                        newMatrixData[clauseId] = [{
                            id: `${clauseId}_req_0`,
                            requirement: desc,
                            evidenceInput: "",
                            status: 'pending'
                        }];
                    }
                });
                return { ...p, matrixData: newMatrixData };
            }
            return p;
        }));

        const activeUpdate = updates.find(u => u.processId === loadedProcessId);
        if (activeUpdate) {
             setMatrixData(prev => {
                 const next = { ...prev };
                 const standard = standards[standardKey];
                 activeUpdate.clauses.forEach(cid => {
                     if(!next[cid]) {
                         const c = findClauseInStandard(cid, standard);
                         const desc = c?.description || "Requirement";
                         next[cid] = [{ id: `${cid}_req_0`, requirement: desc, evidenceInput: "", status: 'pending' }];
                     }
                 });
                 return next;
             });
        }
    };

    const toggleProcessClause = (processId: string, clauseId: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id !== processId) return p;
            const newMatrixData = { ...p.matrixData };
            if (newMatrixData[clauseId]) {
                delete newMatrixData[clauseId];
            } else {
                const standard = standards[standardKey];
                const clause = findClauseInStandard(clauseId, standard);
                const desc = clause?.description || "Requirement";
                newMatrixData[clauseId] = [{
                    id: `${clauseId}_req_0`,
                    requirement: desc,
                    evidenceInput: "",
                    status: 'pending'
                }];
            }
            return { ...p, matrixData: newMatrixData };
        }));

        if (loadedProcessId === processId) {
            setMatrixData(prev => {
                const next = { ...prev };
                if (next[clauseId]) {
                    delete next[clauseId];
                } else {
                    const standard = standards[standardKey];
                    const clause = findClauseInStandard(clauseId, standard);
                    const desc = clause?.description || "Requirement";
                    next[clauseId] = [{
                        id: `${clauseId}_req_0`,
                        requirement: desc,
                        evidenceInput: "",
                        status: 'pending'
                    }];
                }
                return next;
            });
        }
    };

    const addInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                if (!p.interviewees.includes(name)) {
                    return { ...p, interviewees: [...p.interviewees, name] };
                }
            }
            return p;
        }));
    };

    const removeInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                return { ...p, interviewees: p.interviewees.filter(i => i !== name) };
            }
            return p;
        }));
    };

    const addEvidenceTag = (tag: EvidenceTag) => {
        setEvidenceTags(prev => [...prev, tag]);
    };

    const loadKnowledgeForStandard = async (key: string) => {
        try {
            const doc = await KnowledgeStore.getDocument(key);
            if (doc) {
                setKnowledgeBase(doc.content);
                setKnowledgeFileName(doc.fileName);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) { console.error(e); }
    };

    const clearKnowledge = async () => {
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        if (standardKey) {
            await KnowledgeStore.deleteStandardData(standardKey);
        }
    };

    const setKnowledgeData = (content: string, fileName: string) => {
        setKnowledgeBase(content);
        setKnowledgeFileName(fileName);
    };

    const resetSession = () => {
        setStandardKey("");
        setAuditInfo(DEFAULT_AUDIT_INFO);
        setProcesses([]);
        setActiveProcessId(null);
        setLoadedProcessId(null); 
        setEvidence("");
        setMatrixData({});
        setEvidenceTags([]);
        setSelectedClauses([]);
        setAnalysisResult(null);
        setSelectedFindings({});
        setFinalReportText(null);
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        setPrivacySettings(DEFAULT_PRIVACY);
        // Reset Smart Planning
        setAuditSites([]);
        setAuditTeam([]);
        setAuditSchedule([]);
        setAuditPlanConfig(DEFAULT_PLAN_CONFIG);
    };

    const restoreSession = (data: any) => {
        if (data.standardKey) setStandardKey(data.standardKey);
        if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
        if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
        if (data.privacySettings) setPrivacySettings(data.privacySettings);

        if (data.processes && data.processes.length > 0) {
            setProcesses(data.processes);
            if(data.activeProcessId) setActiveProcessId(data.activeProcessId);
        } else if (data.scopes && data.scopes.length > 0) {
             const migrated = data.scopes.map((s: any) => ({
                 ...s,
                 interviewees: [] 
             }));
             setProcesses(migrated);
             if(data.activeScopeId) setActiveProcessId(data.activeScopeId);
        }

        if (data.analysisResult) setAnalysisResult(data.analysisResult);
        if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
        if (data.finalReportText) setFinalReportText(data.finalReportText);

        if (data.auditSites) setAuditSites(data.auditSites);
        if (data.auditTeam) setAuditTeam(data.auditTeam);

        // SAFE RESTORE: MERGE WITH DEFAULT TO PREVENT UNDEFINED ARRAYS
        if (data.auditPlanConfig) {
            setAuditPlanConfig({
                ...DEFAULT_PLAN_CONFIG,
                ...data.auditPlanConfig,
                auditDates: data.auditPlanConfig.auditDates || DEFAULT_PLAN_CONFIG.auditDates
            });
        }

        if (data.auditSchedule) setAuditSchedule(data.auditSchedule);

        if(data.standardKey) loadKnowledgeForStandard(data.standardKey);
    };

    const contextValue = useMemo(() => ({
        standards, standardKey, setStandardKey, customStandards, addCustomStandard, updateStandard, resetStandard,
        auditInfo, setAuditInfo,
        privacySettings, setPrivacySettings,
        auditTypeOptions, addAuditType, deleteAuditType, resetAuditTypes,
        processes, activeProcessId, activeProcess, setActiveProcessId, addProcess, renameProcess, updateProcessCode, updateProcessSites, deleteProcess, batchUpdateProcessClauses, toggleProcessClause,
        addInterviewee, removeInterviewee,
        auditSites, setAuditSites, auditTeam, setAuditTeam, auditPlanConfig, setAuditPlanConfig, auditSchedule, setAuditSchedule,
        evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
        selectedClauses, setSelectedClauses,
        knowledgeBase, knowledgeFileName, loadKnowledgeForStandard, clearKnowledge, setKnowledgeData,
        analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings, finalReportText, setFinalReportText,
        resetSession, restoreSession
    }), [
        standards, standardKey, customStandards, auditInfo, privacySettings, auditTypeOptions,
        processes, activeProcessId, activeProcess,
        auditSites, auditTeam, auditPlanConfig, auditSchedule,
        evidence, matrixData, evidenceTags,
        selectedClauses, knowledgeBase, knowledgeFileName,
        analysisResult, selectedFindings, finalReportText
    ]);

    return (
        <AuditContext.Provider value={contextValue}>
            {children}
        </AuditContext.Provider>
    );
};

export const useAudit = () => {
    const context = useContext(AuditContext);
    if (!context) throw new Error("useAudit must be used within AuditProvider");
    return context;
};

import React, { useState, useMemo, useRef, memo, useCallback, useEffect } from 'react';
import { Icon, GlassDatePicker } from '../UI';
import { useAudit } from '../../contexts/AuditContext';
import { Clause, AuditMember, AuditSite } from '../../types';
import { useUI } from '../../contexts/UIContext';
import { useKeyPool } from '../../contexts/KeyPoolContext';
import { cleanAndParseJSON } from '../../utils';
import { TABS_CONFIG } from '../../constants';
import { generateAuditSchedule } from '../../services/geminiService';

// --- INTERNAL TYPES ---
interface PlanningRowProps {
    clause: Clause;
    level: number;
    processes: any[];
    onSmartToggle: (procId: string, clause: Clause) => void; 
}

interface PlanningViewProps {
    onExport?: (type: 'schedule', lang: 'en' | 'vi', format?: 'txt' | 'docx', extraData?: any) => void;
}

// --- HELPER: Get all descendant IDs ---
const getFlatClauseIds = (clause: Clause): string[] => {
    let ids = [clause.id];
    if (clause.subClauses) {
        clause.subClauses.forEach(sub => {
            ids = [...ids, ...getFlatClauseIds(sub)];
        });
    }
    return ids;
};

// --- MEMOIZED MATRIX ROW COMPONENT ---
const PlanningRow = memo(({ 
    clause, level, processes, onSmartToggle 
}: PlanningRowProps) => {

    const selfAndDescendants = useMemo(() => getFlatClauseIds(clause), [clause]);
    const isParent = clause.subClauses && clause.subClauses.length > 0;

    return (
        <tr className="hover:bg-gray-50 dark:hover:bg-slate-800/30 transition-colors group duration-300 ease-fluid">
            <td className="p-2 border-r border-gray-100 dark:border-slate-800 sticky left-0 bg-white dark:bg-slate-900 group-hover:bg-gray-50 dark:group-hover:bg-slate-800/30 z-10 align-top transition-colors duration-300 ease-fluid">
                <div className={`flex flex-col gap-1 ${level > 0 ? 'ml-4 border-l-2 border-gray-200 dark:border-slate-800 pl-2' : ''}`}>
                    <div className="flex items-center gap-2">
                        <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold whitespace-nowrap ${level === 0 ? 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 border border-slate-200 dark:border-slate-700' : 'text-slate-400'}`}>
                            {clause.code}
                        </span>
                        <span className={`text-xs truncate ${level === 0 ? 'font-bold text-slate-800 dark:text-slate-200' : 'font-medium text-slate-600 dark:text-slate-400'}`}>
                            {clause.title}
                        </span>
                    </div>
                </div>
            </td>
            {processes.map(p => {
                let status: 'all' | 'some' | 'none' = 'none';

                if (isParent) {
                    const activeCount = selfAndDescendants.reduce((acc, id) => acc + (p.matrixData[id] ? 1 : 0), 0);
                    if (activeCount === selfAndDescendants.length) status = 'all';
                    else if (activeCount > 0) status = 'some';
                } else {
                    status = p.matrixData[clause.id] ? 'all' : 'none';
                }

                return (
                    <td key={`${p.id}_${clause.id}`} className="p-1 text-center border-r border-gray-50 dark:border-slate-800/50 last:border-0 relative align-middle">
                        <div className="flex justify-center">
                            <button
                                onClick={() => onSmartToggle(p.id, clause)}
                                className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all duration-300 ease-spring ${
                                    status === 'all' 
                                        ? 'bg-emerald-500 text-white shadow-sm shadow-emerald-500/40 transform scale-105' 
                                        : status === 'some'
                                            ? 'bg-orange-100 dark:bg-orange-900/30 text-orange-500 border border-orange-200 dark:border-orange-800'
                                            : 'bg-slate-50 dark:bg-slate-800/50 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-300'
                                }`}
                                title={status === 'all' ? "Fully Planned" : status === 'some' ? "Partially Planned (Click to Fill)" : "Click to Plan"}
                            >
                                {status === 'all' && (isParent ? <Icon name="CheckCircle2" size={14}/> : <Icon name="CheckThick" size={14}/>)}
                                {status === 'some' && <div className="w-2.5 h-2.5 rounded-full bg-orange-500"></div>}
                            </button>
                        </div>
                    </td>
                );
            })}
        </tr>
    );
}, (prev, next) => {
    if (prev.processes.length !== next.processes.length) return false;

    const hasChange = prev.processes.some((pp, idx) => {
        const np = next.processes[idx];
        return pp.matrixData !== np.matrixData;
    });

    return !hasChange; 
});


export const PlanningView: React.FC<PlanningViewProps> = ({ onExport }) => {
    const { 
        standards, standardKey, processes, auditInfo,
        addProcess, batchUpdateProcessClauses, toggleProcessClause,
        auditSites, setAuditSites, auditTeam, setAuditTeam, auditPlanConfig, setAuditPlanConfig,
        auditSchedule, setAuditSchedule, updateProcessCode, updateProcessSites
    } = useAudit();

    const { showToast, setSidebarOpen } = useUI();
    const { getActiveKey } = useKeyPool();

    // Tab State
    const [activeTab, setActiveTab] = useState<'matrix' | 'resources'>('matrix');

    // Matrix View State
    const [search, setSearch] = useState("");
    const searchInputRef = useRef<HTMLInputElement>(null);
    const logsEndRef = useRef<HTMLDivElement>(null);
    const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());

    // Logistics State
    const [newSite, setNewSite] = useState<AuditSite>({ id: "", name: "", address: "", scope: "", isMain: false, employeeCount: 0 });
    const [editingMemberId, setEditingMemberId] = useState<string | null>(null);
    const [newMember, setNewMember] = useState<Partial<AuditMember>>({ name: "", role: "Auditor", competencyCodes: "", manDays: 1, isRemote: false, availability: "" });

    // Export Lang State
    const [exportLanguage, setExportLanguage] = useState<'en' | 'vi'>('en');

    // Dates Logic (New: Calendar Modal)
    const [isCalendarOpen, setIsCalendarOpen] = useState(false);

    // Site Editing State
    const [editingSiteId, setEditingSiteId] = useState<string | null>(null);
    const [tempSite, setTempSite] = useState<AuditSite | null>(null);

    // AI Generation State
    const [isGenerating, setIsGenerating] = useState(false);
    const [genProgress, setGenProgress] = useState(0);
    const [genLogs, setGenLogs] = useState<string[]>([]);

    // --- NEW: DYNAMIC AGENDA COLUMNS ---
    const [agendaColumns, setAgendaColumns] = useState(['timeSlot', 'siteName', 'processName', 'activity', 'auditorName', 'clauseRefs']);
    const [draggedColumn, setDraggedColumn] = useState<string | null>(null);

    const COLUMN_LABELS: Record<string, string> = {
        timeSlot: "Time",
        siteName: "Site",
        auditorName: "Auditor",
        clauseRefs: "Clauses",
        activity: "Activity",
        processName: "Process / Auditee"
    };

    const currentStandard = standards[standardKey];
    const themeConfig = TABS_CONFIG.find(t => t.id === 'planning')!;

    // Auto-scroll logs
    useEffect(() => {
        if (isGenerating && logsEndRef.current) {
            logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [genLogs, isGenerating]);

    // --- HELPER: LOGGING ---
    const addLog = (msg: string) => setGenLogs(prev => [...prev, msg]);

    // --- AGENDA DRAG & DROP LOGIC ---
    const handleDragStart = (e: React.DragEvent, colId: string) => {
        setDraggedColumn(colId);
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setDragImage(e.currentTarget as Element, 20, 20);
    };

    const handleDragOver = (e: React.DragEvent, colId: string) => {
        e.preventDefault();
        if (!draggedColumn || draggedColumn === colId) return;

        const newCols = [...agendaColumns];
        const draggedIdx = newCols.indexOf(draggedColumn);
        const targetIdx = newCols.indexOf(colId);

        // Swap
        newCols.splice(draggedIdx, 1);
        newCols.splice(targetIdx, 0, draggedColumn);

        setAgendaColumns(newCols);
    };

    const handleDragEnd = () => {
        setDraggedColumn(null);
    };

    // --- AGENDA SORTING & MERGING LOGIC ---
    const getSortedSchedule = (daySchedule: any[]) => {
        return [...daySchedule].sort((a, b) => {
            for (const col of agendaColumns) {
                // Get values
                const valA = a[col] || "";
                const valB = b[col] || "";

                if (valA === valB) continue; 

                // Special handling for Time Slots
                return valA.toString().localeCompare(valB.toString(), undefined, { numeric: true, sensitivity: 'base' });
            }
            return 0;
        });
    };

    const calculateRowSpans = (data: any[], columns: string[]) => {
        const rowSpans: Record<string, number> = {}; 

        for (let rowIdx = 0; rowIdx < data.length; rowIdx++) {
            for (let colIdx = 0; colIdx < columns.length; colIdx++) {
                const key = `${rowIdx}_${colIdx}`;
                if (rowSpans[key] === 0) continue; 
                rowSpans[key] = 1;
            }
        }

        for (let colIdx = 0; colIdx < columns.length; colIdx++) {
            const colName = columns[colIdx];
            for (let rowIdx = 0; rowIdx < data.length; rowIdx++) {
                const key = `${rowIdx}_${colIdx}`;
                if (rowSpans[key] === 0) continue; 

                const currentVal = data[rowIdx][colName];

                for (let nextIdx = rowIdx + 1; nextIdx < data.length; nextIdx++) {
                    const nextVal = data[nextIdx][colName];
                    const nextKey = `${nextIdx}_${colIdx}`;

                    let parentMatch = true;
                    if (colName === 'auditorName' || colName === 'processName') {
                        const valSiteA = data[rowIdx]['siteName'];
                        const valSiteB = data[nextIdx]['siteName'];
                        if (valSiteA !== valSiteB) parentMatch = false;
                    } else if (colIdx > 0) {
                        for (let p = 0; p < colIdx; p++) {
                            if (data[rowIdx][columns[p]] !== data[nextIdx][columns[p]]) {
                                parentMatch = false;
                                break;
                            }
                        }
                    }

                    if (currentVal === nextVal && parentMatch) {
                        rowSpans[key]++;
                        rowSpans[nextKey] = 0; 
                    } else {
                        break; 
                    }
                }
            }
        }
        return rowSpans;
    };

    // --- MATRIX LOGIC START ---
    const getPDCAStyle = (groupId: string) => {
        const key = groupId.toUpperCase();
        if (key.includes('PLAN')) return 'bg-orange-50 hover:bg-orange-100 dark:bg-orange-900/20 dark:hover:bg-orange-900/30 text-orange-700 dark:text-orange-400 border-l-4 border-orange-500';
        if (key.includes('SUPPORT')) return 'bg-blue-50 hover:bg-blue-100 dark:bg-blue-900/20 dark:hover:bg-blue-900/30 text-blue-700 dark:text-blue-400 border-l-4 border-blue-500';
        if (key.includes('DO')) return 'bg-cyan-50 hover:bg-cyan-100 dark:bg-cyan-900/20 dark:hover:bg-cyan-900/30 text-cyan-700 dark:text-cyan-400 border-l-4 border-cyan-500';
        if (key.includes('CHECK') || key.includes('ACT')) return 'bg-emerald-50 hover:bg-emerald-100 dark:bg-emerald-900/20 dark:hover:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 border-l-4 border-emerald-500';
        if (key.includes('ANNEX')) return 'bg-purple-50 hover:bg-purple-100 dark:bg-purple-900/20 dark:hover:bg-purple-900/30 text-purple-700 dark:text-purple-400 border-l-4 border-purple-500';
        return `${themeConfig.bgSoft} border-l-4 ${themeConfig.borderClass} ${themeConfig.textClass}`;
    };

    const getGroupClauses = useMemo(() => (clauses: Clause[]) => {
        const flat: { clause: Clause, level: number }[] = [];
        const traverse = (list: Clause[], level: number) => {
            list.forEach(c => {
                flat.push({ clause: c, level });
                if(c.subClauses) traverse(c.subClauses, level + 1);
            });
        };
        traverse(clauses, 0);
        return flat;
    }, []); 

    const handleSmartToggle = useCallback((processId: string, clause: Clause) => {
        const proc = processes.find(p => p.id === processId);
        if (!proc) return;

        const allIds = getFlatClauseIds(clause);
        const isGroup = allIds.length > 1;

        if (!isGroup) {
            toggleProcessClause(processId, clause.id);
        } else {
            const activeCount = allIds.reduce((acc, id) => acc + (proc.matrixData[id] ? 1 : 0), 0);
            const isFullyActive = activeCount === allIds.length;

            if (isFullyActive) {
                allIds.forEach(id => {
                    if (proc.matrixData[id]) toggleProcessClause(processId, id);
                });
            } else {
                const toAdd = allIds.filter(id => !proc.matrixData[id]);
                if (toAdd.length > 0) {
                    batchUpdateProcessClauses([{ processId, clauses: toAdd }]);
                }
            }
        }
    }, [processes, toggleProcessClause, batchUpdateProcessClauses]);

    const handleGroupToggle = (e: React.MouseEvent, processId: string, clausesInGroup: Clause[]) => {
        e.stopPropagation();
        const flatIds: string[] = [];
        const traverse = (list: Clause[]) => list.forEach(c => {
            flatIds.push(c.id);
            if(c.subClauses) traverse(c.subClauses);
        });
        traverse(clausesInGroup);

        const proc = processes.find(p => p.id === processId);
        if (!proc) return;

        const allSelected = flatIds.every(cid => !!proc.matrixData[cid]);

        if (allSelected) {
            flatIds.forEach(cid => {
                if (proc.matrixData[cid]) toggleProcessClause(processId, cid);
            });
        } else {
            const toAdd = flatIds.filter(cid => !proc.matrixData[cid]);
            batchUpdateProcessClauses([{ processId, clauses: toAdd }]);
        }
    };

    const toggleGroupCollapse = (groupId: string) => {
        setCollapsedGroups(prev => {
            const next = new Set(prev);
            if (next.has(groupId)) next.delete(groupId);
            else next.add(groupId);
            return next;
        });
    };

    const areAllCollapsed = useMemo(() => {
        if (!currentStandard) return false;
        return currentStandard.groups.every(g => collapsedGroups.has(g.id));
    }, [currentStandard, collapsedGroups]);

    const handleToggleAll = () => {
        if (!currentStandard) return;
        const allGroupIds = currentStandard.groups.map(g => g.id);
        if (areAllCollapsed) setCollapsedGroups(new Set());
        else setCollapsedGroups(new Set(allGroupIds));
    };

    const coverageStats = useMemo(() => {
        if (!currentStandard) return { percent: 0, covered: 0, total: 0 };
        let total = 0;
        const traverse = (list: Clause[]) => list.forEach(c => { total++; if(c.subClauses) traverse(c.subClauses); });
        currentStandard.groups.forEach(g => traverse(g.clauses));

        if (total === 0) return { percent: 0, covered: 0, total: 0 };

        const coveredSet = new Set<string>();
        processes.forEach(p => {
            Object.keys(p.matrixData).forEach(cid => coveredSet.add(cid));
        });

        return {
            percent: Math.round((coveredSet.size / total) * 100),
            covered: coveredSet.size,
            total: total
        };
    }, [currentStandard, processes]);

    const radius = 24;
    const circumference = 2 * Math.PI * radius;
    const strokeDashoffset = circumference - (coverageStats.percent / 100) * circumference;

    const filteredGroups = useMemo(() => {
        if (!currentStandard) return [];
        if (!search) return currentStandard.groups;

        const term = search.toLowerCase();
        return currentStandard.groups.map(g => {
            const matchingClauses = g.clauses.filter(c => {
                const matchSelf = c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term);
                const matchSub = c.subClauses?.some(s => s.code.toLowerCase().includes(term) || s.title.toLowerCase().includes(term));
                return matchSelf || matchSub;
            });
            return matchingClauses.length > 0 ? { ...g, clauses: matchingClauses } : null;
        }).filter(g => g !== null) as typeof currentStandard.groups;
    }, [currentStandard, search]);
    // --- MATRIX LOGIC END ---

    // --- SITE MANAGEMENT LOGIC ---
    // Constraint Logic for Employee Count
    const totalEmployees = auditInfo.totalEmployees || 0;
    const allocatedEmployees = auditSites.reduce((sum, s) => sum + (s.employeeCount || 0), 0);
    const unallocatedEmployees = Math.max(0, totalEmployees - allocatedEmployees);

    const handleAddSite = () => {
        if (!newSite.name.trim()) return;

        // Validation removed to allow auto-sync of total employees
        // if ((newSite.employeeCount || 0) > unallocatedEmployees) { ... }

        const site: AuditSite = {
            id: `site_${Date.now()}`,
            name: newSite.name.trim(),
            address: newSite.address || "",
            scope: newSite.scope || "",
            isMain: newSite.isMain,
            employeeCount: newSite.employeeCount || 0
        };
        // CHANGE: Append to end (Chronological Entry Order)
        setAuditSites([...auditSites, site]);
        setNewSite({ id: "", name: "", address: "", scope: "", isMain: false, employeeCount: 0 });
    };

    const handleStartEditSite = (site: AuditSite) => {
        setEditingSiteId(site.id);
        setTempSite({ ...site });
    };

    const handleSaveSite = () => {
        if (tempSite && editingSiteId) {
            // Validation removed to allow auto-sync of total employees
            // const otherSitesAllocated = ...
            // if ((tempSite.employeeCount || 0) > remainingForThis) { ... }

            setAuditSites(prev => prev.map(s => s.id === editingSiteId ? tempSite : s));
            setEditingSiteId(null);
            setTempSite(null);
        }
    };

    const handleCancelEditSite = () => {
        setEditingSiteId(null);
        setTempSite(null);
    };

    // --- TEAM MANAGEMENT LOGIC ---
    const handleSaveMember = () => {
        if (!newMember.name?.trim()) return;

        if (editingMemberId) {
            setAuditTeam(prev => prev.map(m => m.id === editingMemberId ? { ...m, ...newMember } as AuditMember : m));
            setEditingMemberId(null);
        } else {
            const member: AuditMember = {
                id: `mem_${Date.now()}`,
                name: newMember.name.trim(),
                role: newMember.role as any,
                competencyCodes: newMember.competencyCodes?.trim() || "",
                manDays: newMember.manDays || 1,
                isRemote: newMember.isRemote || false,
                availability: newMember.availability || ""
            };
            // CHANGE: Append to end (Chronological Entry Order)
            setAuditTeam([...auditTeam, member]);
        }
        setNewMember({ name: "", role: "Auditor", competencyCodes: "", manDays: 1, isRemote: false, availability: "" });
    };

    const handleEditMember = (m: AuditMember) => {
        setEditingMemberId(m.id);
        setNewMember({ ...m });
    };

    // --- DATE MANAGEMENT LOGIC (Updated to use GlassDatePicker) ---
    const handleUpdateDates = (newDates: string[]) => {
        setAuditPlanConfig({ ...auditPlanConfig, auditDates: newDates });
    };

    const handleRemoveDate = (date: string) => {
        const currentDates = Array.isArray(auditPlanConfig.auditDates) ? auditPlanConfig.auditDates : [];
        const newDates = currentDates.filter(d => d !== date);
        setAuditPlanConfig({ ...auditPlanConfig, auditDates: newDates });
    };

    const handleGenerateSchedule = async () => {
        const key = getActiveKey();
        if (!key) { showToast("API Key Required."); return; }
        if (auditTeam.length === 0) { showToast("Please add at least one auditor."); return; }
        if (processes.length === 0) { showToast("No processes found to schedule."); return; }

        const safeDates = Array.isArray(auditPlanConfig.auditDates) ? auditPlanConfig.auditDates : [];
        if (safeDates.length === 0) { showToast("Please add at least one audit date."); return; }

        setIsGenerating(true);
        setGenProgress(5);
        setGenLogs(["Initializing Smart Planner...", "Validating resources and process map..."]);

        try {
            // SIMULATE STEPS for Visualization (Since API call is single-shot)
            setTimeout(() => { setGenProgress(20); addLog("Analyzing Auditor Competencies..."); }, 800);
            setTimeout(() => { setGenProgress(40); addLog(`Mapping ${processes.length} Processes to Sites...`); }, 2000);
            setTimeout(() => { setGenProgress(60); addLog("Optimizing time slots & balancing workload..."); }, 3500);
            setTimeout(() => { setGenProgress(80); addLog("Finalizing Agenda Structure..."); }, 5000);

            const resultJson = await generateAuditSchedule(
                auditSites,
                auditTeam,
                processes,
                auditPlanConfig,
                key.key,
                key.activeModel,
                { name: auditInfo.auditor, code: auditInfo.leadAuditorCode }
            );

            // Clean JSON
            const schedule = cleanAndParseJSON(resultJson);

            if (Array.isArray(schedule) && schedule.length > 0) {
                setGenProgress(100);
                addLog("Success! Rendering Schedule...");
                await new Promise(r => setTimeout(r, 800)); // Small delay to show 100%
                setAuditSchedule(schedule);
                showToast("Schedule Generated Successfully!");
            } else {
                throw new Error("AI returned invalid schedule format. Try again.");
            }
        } catch (e: any) {
            console.error(e);
            addLog(`ERROR: ${e.message}`);
            showToast("Planning Failed: Check Logs.");
            await new Promise(r => setTimeout(r, 2000)); // Delay to show error log
        } finally {
            setIsGenerating(false);
        }
    };
    // --- RESOURCES LOGIC END ---

    const handleSelectStandardFocus = () => {
        setSidebarOpen(true);
        setTimeout(() => {
            const el = document.getElementById('sidebar-standard-select');
            if (el) { el.focus(); try { (el as any).showPicker(); } catch (e) { el.click(); } }
        }, 300);
    };

    if (!currentStandard) return (
        <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/30 dark:bg-slate-900/30 rounded-2xl border border-dashed border-gray-200 dark:border-slate-800 m-4 animate-fade-in-up">
            <Icon name="Book" size={48} className="mb-4 opacity-20"/>
            <p className="font-bold text-slate-500">No Standard Selected</p>
            <button onClick={handleSelectStandardFocus} className="mt-6 px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg text-xs font-bold flex items-center gap-2">
                <Icon name="LayoutList" size={16}/> Select Standard
            </button>
        </div>
    );

    const safeAuditDates = Array.isArray(auditPlanConfig.auditDates) ? auditPlanConfig.auditDates : [];

    return (
        <div className="h-full flex flex-col animate-fade-in-up gap-4 relative">

            {/* Header / Stats / Tab Switcher */}
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row gap-4 items-center justify-between shrink-0 transition-colors duration-500 ease-fluid">
                <div className="flex items-center gap-6">
                    <div className="relative w-16 h-16 flex items-center justify-center shrink-0">
                        <svg className="transform -rotate-90 w-16 h-16">
                            <circle cx="32" cy="32" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-200 dark:text-slate-700" />
